module RefModule (
    input [7:0] data_in,
    input [3:0] expected_checksum,
    output reg valid
);
    integer i;
    reg [3:0] unused_computed_checksum;

    always @(*) begin
        unused_computed_checksum = 4'b0000;
        for (i = 0; i < 8; i = i + 1) begin
            unused_computed_checksum = unused_computed_checksum + data_in[i];
        end
        valid = (unused_computed_checksum == expected_checksum);
    end
endmodule
